# @cctt_verify {"v":2,"sym":"sympy.combinatorics.tests.test_util.test_strip","kind":"function","src_hash":"2a80282bf57f1ed2","in":{"base":"Any"},"out":{"base":"Any","pred":"res1[0] == identity and res1[1] == len(D.base) + 1 and res2[0] == not_member1 and res2[1] == len(D.base) + 1 and res3[0] != identity and res3[1] == 2"},"spec":{"lhs":"test_strip()","rhs":"test_strip produces the expected output","over":{"base":"Any"},"name":"test_strip_correct"},"guarantee":"test_strip produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.combinatorics.tests.test_util.test_strip_correct","statement":"Path(test_strip(x), test_strip produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"63b8ec3086f01fca"}
def test_strip():
    D = DihedralGroup(5)
    D.schreier_sims()
    member = Permutation([4, 0, 1, 2, 3])
    not_member1 = Permutation([0, 1, 4, 3, 2])
    not_member2 = Permutation([3, 1, 4, 2, 0])
    identity = Permutation([0, 1, 2, 3, 4])
    res1 = _strip(member, D.base, D.basic_orbits, D.basic_transversals)
    res2 = _strip(not_member1, D.base, D.basic_orbits, D.basic_transversals)
    res3 = _strip(not_member2, D.base, D.basic_orbits, D.basic_transversals)
    assert res1[0] == identity
    assert res1[1] == len(D.base) + 1
    assert res2[0] == not_member1
    assert res2[1] == len(D.base) + 1
    assert res3[0] != identity
    assert res3[1] == 2


