# @cctt_verify {"v":2,"sym":"sympy.combinatorics.tests.test_util.test_orbits_transversals_from_bsgs","kind":"function","src_hash":"762af143a5c6b5cd","in":{"base":"Any"},"out":{"base":"Any","pred":"S.order() == order and transversals[i][el](base[i]) == el and transversals[i][el](base[j]) == base[j]"},"spec":{"lhs":"test_orbits_transversals_from_bsgs()","rhs":"test_orbits_transversals_from_bsgs produces the expected output","over":{"base":"Any"},"name":"test_orbits_transversals_from_bsgs_correct"},"guarantee":"test_orbits_transversals_from_bsgs produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.combinatorics.tests.test_util.test_orbits_transversals_from_bsgs_correct","statement":"Path(test_orbits_transversals_from_bsgs(x), test_orbits_transversals_from_bsgs produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"9a38e028373f1b76"}
def test_orbits_transversals_from_bsgs():
    S = SymmetricGroup(4)
    S.schreier_sims()
    base = S.base
    strong_gens = S.strong_gens
    strong_gens_distr = _distribute_gens_by_base(base, strong_gens)
    result = _orbits_transversals_from_bsgs(base, strong_gens_distr)
    orbits = result[0]
    transversals = result[1]
    base_len = len(base)
    for i in range(base_len):
        for el in orbits[i]:
            assert transversals[i][el](base[i]) == el
            for j in range(i):
                assert transversals[i][el](base[j]) == base[j]
    order = 1
    for i in range(base_len):
        order *= len(orbits[i])
    assert S.order() == order


